cursor_x = [5]

def on_mouse_move(event):
    if event.inaxes == ax:  # Check if the cursor is inside the axes
        cursor_x[0] = event.xdata  # Update the cursor's x-position

fig.canvas.mpl_connect('motion_notify_event', on_mouse_move)

line, = ax.plot([], [])

#ax.set_xlim(-2, 4)
#ax.set_ylim(-2, 3)

frame_text = ax.text(0.5, 0.9, '', transform=ax.transAxes, fontsize=12, ha='center')


def update(frame):
    x = np.linspace(-1, 4, 400)         # Example x data
    y = (x1-cursor_x[0])/(2*np.sin(frame/100))        # Update y data
    line.set_data(x, y)                 # Update the line data
    cursor_line.set_data([cursor_x[0], cursor_x[0]], [-1, 1])
    frame_text.set_text(f'k: {2*np.sin(frame/100)}, c = {cursor_x}')  # Update frame text
    return line, cursor_line, frame_text                     # Return the updated object(s)

ani = FuncAnimation(fig, update, frames=400, interval=50, blit=True)



